document.addEventListener('DOMContentLoaded',()=>{const b=document.getElementById('themeToggle');if(localStorage.getItem('theme')==='dark')document.body.classList.add('dark');if(b){b.textContent=document.body.classList.contains('dark')?'☀':'☾';b.onclick=()=>{document.body.classList.toggle('dark');localStorage.setItem('theme',document.body.classList.contains('dark')?'dark':'light');b.textContent=document.body.classList.contains('dark')?'☀':'☾';};}});